import { defineConfig } from 'astro/config';
import sitemap from '@astrojs/sitemap';
import sanity from '@sanity/astro';
import react from '@astrojs/react';
import vercel from '@astrojs/vercel';
import pagefind from 'astro-pagefind';

export default defineConfig({
  site: 'https://ficcc.org',
  // Astro 5 removed output:'hybrid' — static + adapter is the equivalent,
  // enabling per-page SSR opt-in via `export const prerender = false`.
  output: 'static', // hybrid equivalent with adapter
  adapter: vercel(),
  integrations: [
    sitemap({
      i18n: {
        defaultLocale: 'en',
        locales: {
          en: 'en',
          zh: 'zh',
        },
      },
    }),
    sanity({
      projectId: import.meta.env.SANITY_PROJECT_ID || 'placeholder',
      dataset: import.meta.env.SANITY_DATASET || 'production',
      useCdn: false, // false for static builds per @sanity/astro docs
      stega: {
        studioUrl: import.meta.env.PUBLIC_SANITY_PREVIEW_URL || 'http://localhost:3333',
      },
    }),
    react(),
    pagefind(),
  ],
  i18n: {
    defaultLocale: 'en',
    locales: ['en', 'zh'],
    routing: {
      prefixDefaultLocale: false,
    },
  },
});

{
  "headers": [
    {
      "source": "/(.*)",
      "headers": [
        { "key": "X-Content-Type-Options", "value": "nosniff" },
        { "key": "X-Frame-Options", "value": "DENY" },
        { "key": "X-XSS-Protection", "value": "1; mode=block" },
        { "key": "Referrer-Policy", "value": "strict-origin-when-cross-origin" },
        { "key": "Permissions-Policy", "value": "camera=(), microphone=(), geolocation=()" },
        { "key": "Strict-Transport-Security", "value": "max-age=63072000; includeSubDomains; preload" },
        {
          "key": "Content-Security-Policy",
          "value": "default-src 'self'; script-src 'self' 'unsafe-inline' https://challenges.cloudflare.com https://www.youtube-nocookie.com; style-src 'self' 'unsafe-inline'; font-src 'self'; img-src 'self' https://cdn.sanity.io data:; frame-src https://www.youtube-nocookie.com https://www.youtube.com https://challenges.cloudflare.com https://www.paypal.com; connect-src 'self' https://*.sanity.io https://*.vercel-analytics.com; media-src 'self' https://cdn.sanity.io"
        }
      ]
    },
    {
      "source": "/fonts/(.*)",
      "headers": [
        { "key": "Cache-Control", "value": "public, max-age=31536000, immutable" }
      ]
    }
  ],
  "redirects": [
    {
      "source": "/",
      "has": [{ "type": "host", "value": "cm.ficcc.org" }],
      "destination": "https://ficcc.org/zh/",
      "permanent": true
    },
    {
      "source": "/home/about/",
      "has": [{ "type": "host", "value": "cm.ficcc.org" }],
      "destination": "https://ficcc.org/zh/about",
      "permanent": true
    },
    {
      "source": "/home/faith/",
      "has": [{ "type": "host", "value": "cm.ficcc.org" }],
      "destination": "https://ficcc.org/zh/about/beliefs",
      "permanent": true
    },
    {
      "source": "/home/sermons/",
      "has": [{ "type": "host", "value": "cm.ficcc.org" }],
      "destination": "https://ficcc.org/zh/sermons",
      "permanent": true
    },
    {
      "source": "/home/worship/",
      "has": [{ "type": "host", "value": "cm.ficcc.org" }],
      "destination": "https://ficcc.org/zh/sundays",
      "permanent": true
    },
    {
      "source": "/home/fellowships/",
      "has": [{ "type": "host", "value": "cm.ficcc.org" }],
      "destination": "https://ficcc.org/zh/ministries",
      "permanent": true
    },
    {
      "source": "/home/%E6%95%99%E6%9C%83%E4%BA%8B%E5%B7%A5/",
      "has": [{ "type": "host", "value": "cm.ficcc.org" }],
      "destination": "https://ficcc.org/zh/ministries",
      "permanent": true
    },
    {
      "source": "/home/教會事工/",
      "has": [{ "type": "host", "value": "cm.ficcc.org" }],
      "destination": "https://ficcc.org/zh/ministries",
      "permanent": true
    },
    {
      "source": "/home/contact/",
      "has": [{ "type": "host", "value": "cm.ficcc.org" }],
      "destination": "https://ficcc.org/zh/contact",
      "permanent": true
    },
    {
      "source": "/:path*",
      "has": [{ "type": "host", "value": "cm.ficcc.org" }],
      "destination": "https://ficcc.org/zh/",
      "permanent": true
    }
  ]
}
